INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Crunch', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Kneel below a high pulley that contains a rope attachment.','Grasp cable rope attachment and lower the rope until your hands are placed next to your face.','Flex your hips slightly and allow the weight to hyperextend the lower back. This will be your starting position.','With the hips stationary, flex the waist as you contract the abs so that the elbows travel towards the middle of the thighs. Exhale as you perform this portion of the movement and hold the contraction for a second.','Slowly return to the starting position as you inhale. Tip: Make sure that you keep constant tension on the abs throughout the movement. Also, do not choose a weight so heavy that the lower back handles the brunt of the work.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Deadlifts', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Move the cables to the bottom of the towers and select an appropriate weight. Stand directly in between the uprights.','To begin, squat down be flexing your hips and knees until you can reach the handles.','After grasping them, begin your ascent. Driving through your heels extend your hips and knees keeping your hands hanging at your side. Keep your head and chest up throughout the movement.','After reaching a full standing position, Return to the starting position and repeat.'], ARRAY['quadriceps'], ARRAY['forearms','glutes','hamstrings','lower back'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Hammer Curls - Rope Attachment', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Attach a rope attachment to a low pulley and stand facing the machine about 12 inches away from it.','Grasp the rope with a neutral (palms-in) grip and stand straight up keeping the natural arch of the back and your torso stationary.','Put your elbows in by your side and keep them there stationary during the entire movement. Tip: Only the forearms should move; not your upper arms. This will be your starting position.','Using your biceps, pull your arms up as you exhale until your biceps touch your forearms. Tip: Remember to keep the elbows in and your upper arms stationary.','After a 1 second contraction where you squeeze your biceps, slowly start to bring the weight back to the original position.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Hip Adduction', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Stand in front of a low pulley facing forward with one leg next to the pulley and the other one away.','Attach the ankle cuff to the cable and also to the ankle of the leg that is next to the pulley.','Now step out and away from the stack with a wide stance and grasp the bar of the pulley system.','Stand on the foot that does not have the ankle cuff (the far foot) and allow the leg with the cuff to be pulled towards the low pulley. This will be your starting position.','Now perform the movement by moving the leg with the ankle cuff in front of the far leg by using the inner thighs to abduct the hip. Breathe out during this portion of the movement.','Slowly return to the starting position as you breathe in.','Repeat for the recommended amount of repetitions and then repeat the same movement with the opposite leg.'], ARRAY['quadriceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Incline Pushdown', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Lie on incline an bench facing away from a high pulley machine that has a straight bar attachment on it.','Grasp the straight bar attachment overhead with a pronated (overhand; palms down) shoulder width grip and extend your arms in front of you. The bar should be around 2 inches away from your upper thighs. This will be your starting position.','Keeping the upper arms stationary, lift your arms back in a semi circle until the bar is straight over your head. Breathe in during this portion of the movement.','Slowly go back to the starting position using your lats and hold the contraction once you reach the starting position. Breathe out during the execution of this movement.','Repeat for the recommended amount of repetitions.'], ARRAY['lats'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Incline Triceps Extension', 'cable', true, 'cable', 'beginner', 'push', 'isolation', ARRAY['Lie on incline an bench facing away from a high pulley machine that has a straight bar attachment on it.','Grasp the straight bar attachment overhead with a pronated (overhand; palms down) narrow grip (less than shoulder width) and keep your elbows tucked in to your sides. Your upper arms should create around a 25 degree angle when measured from the floor.','Keeping the upper arms stationary, extend the arms as you flex the triceps. Breathe out during this portion of the movement and hold the contraction for a second.','Slowly go back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Internal Rotation', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Sit next to a low pulley sideways (with legs stretched in front of you or crossed) and grasp the single hand cable attachment with the arm nearest to the cable. Tip: If you can adjust the pulley''s height, you can use a flat bench to sit on instead.','Position the elbow against your side with the elbow bent at 90° and the arm pointing towards the pulley. This will be your starting position.','Pull the single hand cable attachment toward your body by internally rotating your shoulder until your forearm is across your abs. You will be creating an imaginary semi-circle. Tip: The forearm should be perpendicular to your torso at all times.','Slowly go back to the initial position.','Repeat for the recommended amount of repetitions and then repeat the movement with the next arm.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Iron Cross', 'cable', true, 'cable', 'beginner', 'push', 'isolation', ARRAY['Begin by moving the pulleys to the high position, select the resistance to be used, and take a handle in each hand.','Stand directly between both pulleys with your arms extended out to your sides. Your head and chest should be up while your arms form a T. This will be your starting position.','Keeping the elbows extended, pull your arms straight to your sides.','Return your arms back to the starting position after a pause at the peak contraction.','Continue the movement for the prescribed number of repetitions.'], ARRAY['chest'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Judo Flip', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Connect a rope attachment to a tower, and move the cable to the lowest pulley position. Stand with your side to the cable with a wide stance, and grab the rope with both hands.','Twist your body away from the pulley as you bring the rope over your shoulder like you''re performing a judo flip.','Shift your weight between your feet as you twist and crunch forward, pulling the cable downward.','Return to the starting position and repeat until failure.','Then, reposition and repeat the same series of movements on the opposite side.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Lying Triceps Extension', 'cable', true, 'cable', 'beginner', 'push', 'isolation', ARRAY['Lie on a flat bench and grasp the straight bar attachment of a low pulley with a narrow overhand grip. Tip: The easiest way to do this is to have someone hand you the bar as you lay down.','With your arms extended, position the bar over your torso. Your arms and your torso should create a 90-degree angle. This will be your starting position.','Lower the bar by bending at the elbow while keeping the upper arms stationary and elbows in. Go down until the bar lightly touches your forehead. Breathe in as you perform this portion of the movement.','Flex the triceps as you lift the bar back to its starting position. Exhale as you perform this portion of the movement.','Hold for a second at the contracted position and repeat for the recommended amount of repetitions.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable One Arm Tricep Extension', 'cable', true, 'cable', 'beginner', 'push', 'isolation', ARRAY['With your right hand, grasp a single handle attached to the high-cable pulley using a supinated (underhand; palms facing up) grip. You should be standing directly in front of the weight stack.','Now pull the handle down so that your upper arm and elbow are locked in to the side of your body. Your upper arm and forearm should form an acute angle (less than 90-degrees). You can keep the other arm by the waist and you can have one leg in front of you and the other one back for better balance. This will be your starting position.','As you contract the triceps, move the single handle attachment down to your side until your arm is straight. Breathe out as you perform this movement. Tip: Only the forearms should move. Your upper arms should remain stationary at all times.','Squeeze the triceps and hold for a second in this contracted position.','Slowly return the handle to the starting position.','Repeat for the recommended amount of repetitions and then perform the same movement with the other arm.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Preacher Curl', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Place a preacher bench about 2 feet in front of a pulley machine.','Attach a straight bar to the low pulley.','Sit at the preacher bench with your elbow and upper arms firmly on top of the bench pad and have someone hand you the bar from the low pulley.','Grab the bar and fully extend your arms on top of the preacher bench pad. This will be your starting position.','Now start pilling the weight up towards your shoulders and squeeze the biceps hard at the top of the movement. Exhale as you perform this motion. Also, hold for a second at the top.','Now slowly lower the weight to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Rear Delt Fly', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Adjust the pulleys to the appropriate height and adjust the weight. The pulleys should be above your head.','Grab the left pulley with your right hand and the right pulley with your left hand, crossing them in front of you. This will be your starting position.','Initiate the movement by moving your arms back and outward, keeping your arms straight as you execute the movement.','Pause at the end of the motion before returning the handles to the start position.'], ARRAY['shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Reverse Crunch', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Connect an ankle strap attachment to a low pulley cable and position a mat on the floor in front of it.','Sit down with your feet toward the pulley and attach the cable to your ankles.','Lie down, elevate your legs and bend your knees at a 90-degree angle. Your legs and the cable should be aligned. If not, adjust the pulley up or down until they are.','With your hands behind your head, bring your knees inward to your torso and elevate your hips off the floor.','Pause for a moment and in a slow and controlled manner drop your hips and bring your legs back to the starting 90-degree angle. You should still have tension on your abs in the resting position.','Repeat the same movement to failure.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Rope Overhead Triceps Extension', 'cable', true, 'cable', 'beginner', 'push', 'isolation', ARRAY['Attach a rope to the bottom pulley of the pulley machine.','Grasping the rope with both hands, extend your arms with your hands directly above your head using a neutral grip (palms facing each other). Your elbows should be in close to your head and the arms should be perpendicular to the floor with the knuckles aimed at the ceiling. This will be your starting position.','Slowly lower the rope behind your head as you hold the upper arms stationary. Inhale as you perform this movement and pause when your triceps are fully stretched.','Return to the starting position by flexing your triceps as you breathe out.','Repeat for the recommended amount of repetitions.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Rope Rear-Delt Rows', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Sit in the same position on a low pulley row station as you would if you were doing seated cable rows for the back.','Attach a rope to the pulley and grasp it with an overhand grip. Your arms should be extended and parallel to the floor with the elbows flared out.','Keep your lower back upright and slide your hips back so that your knees are slightly bent. This will be your starting position.','Pull the cable attachment towards your upper chest, just below the neck, as you keep your elbows up and out to the sides. Continue this motion as you exhale until the elbows travel slightly behind the back. Tip: Keep your upper arms horizontal, perpendicular to the torso and parallel to the floor throughout the motion.','Go back to the initial position where the arms are extended and the shoulders are stretched forward. Inhale as you perform this portion of the movement.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['biceps','middle back'], ARRAY['Pull rope to face, elbows high','Spread rope apart at the end','Squeeze rear delts and upper back','Keep core tight, dont lean back','One of the best exercises for posture'], ARRAY['Pulling too low (becomes a row)','Using too much weight','Excessive body lean'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Russian Twists', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Connect a standard handle attachment, and position the cable to a middle pulley position.','Lie on a stability ball perpendicular to the cable and grab the handle with one hand. You should be approximately arm''s length away from the pulley, with the tension of the weight on the cable.','Grab the handle with both hands and fully extend your arms above your chest. You hands should be directly in-line with the pulley. If not, adjust the pulley up or down until they are.','Keep your hips elevated and abs engaged. Rotate your torso away from the pulley for a full-quarter rotation. Your body should be flat from head to knees.','Pause for a moment and in a slow and controlled manner reset to the starting position. You should still have side tension on the cable in the resting position.','Repeat the same movement to failure.','Then, reposition and repeat the same series of movements on the opposite side.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Seated Crunch', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Seat on a flat bench with your back facing a high pulley.','Grasp the cable rope attachment with both hands (with the palms of the hands facing each other) and place your hands securely over both shoulders. Tip: Allow the weight to hyperextend the lower back slightly. This will be your starting position.','With the hips stationary, flex the waist so the elbows travel toward the hips. Breathe out as you perform this step.','As you inhale, go back to the initial position slowly.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Seated Lateral Raise', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Stand in the middle of two low pulleys that are opposite to each other and place a flat bench right behind you (in perpendicular fashion to you; the narrow edge of the bench should be the one behind you). Select the weight to be used on each pulley.','Now sit at the edge of the flat bench behind you with your feet placed in front of your knees.','Bend forward while keeping your back flat and rest your torso on the thighs.','Have someone give you the single handles attached to the pulleys. Grasp the left pulley with the right hand and the right pulley with the left after you select your weight. The pulleys should run under your knees and your arms will be extended with palms facing each other and a slight bend at the elbows. This will be the starting position.','While keeping the arms stationary, raise the upper arms to the sides until they are parallel to the floor and at shoulder height. Exhale during the execution of this movement and hold the contraction for a second.','Slowly lower your arms to the starting position as you inhale.','Repeat for the recommended amount of repetitions. Tip: Maintain upper arms perpendicular to torso and a fixed elbow position (10 degree to 30 degree angle) throughout exercise.'], ARRAY['shoulders'], ARRAY['middle back','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Shoulder Press', 'cable', true, 'cable', 'beginner', 'push', 'compound', ARRAY['Move the cables to the bottom of the towers and select an appropriate weight.','Stand directly in between the uprights. Grasp the cables and hold them at shoulder height, palms facing forward. This will be your starting position.','Keeping your head and chest up, extend through the elbow to press the handles directly over head.','After pausing at the top, return to the starting position and repeat.'], ARRAY['shoulders'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Shrugs', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Grasp a cable bar attachment that is attached to a low pulley with a shoulder width or slightly wider overhand (palms facing down) grip.','Stand erect close to the pulley with your arms extended in front of you holding the bar. This will be your starting position.','Lift the bar by elevating the shoulders as high as possible as you exhale. Hold the contraction at the top for a second. Tip: The arms should remain extended at all times. Refrain from using the biceps to help lift the bar. Only the shoulders should be moving up and down.','Lower the bar back to the original position.','Repeat for the recommended amount of repetitions.'], ARRAY['traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cable Wrist Curl', 'cable', true, 'cable', 'beginner', 'pull', 'isolation', ARRAY['Start out by placing a flat bench in front of a low pulley cable that has a straight bar attachment.','Use your arms to grab the cable bar with a narrow to shoulder width supinated grip (palms up) and bring them up so that your forearms are resting against the top of your thighs. Your wrists should be hanging just beyond your knees.','Start out by curling your wrist upwards and exhaling. Keep the contraction for a second.','Slowly lower your wrists back down to the starting position while inhaling.','Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Calf-Machine Shoulder Shrug', 'machine', true, 'machine', 'beginner', 'pull', 'isolation', ARRAY['Position yourself on the calf machine so that the shoulder pads are above your shoulders. Your torso should be straight with the arms extended normally by your side. This will be your starting position.','Raise your shoulders up towards your ears as you exhale and hold the contraction for a full second.','Slowly return to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Calf Press', 'machine', true, 'machine', 'beginner', 'push', 'isolation', ARRAY['Adjust the seat so that your legs are only slightly bent in the start position. The balls of your feet should be firmly on the platform.','Select an appropriate weight, and grasp the handles. This will be your starting position.','Straighten the legs by extending the knees, just barely lifting the weight from the stack. Your ankle should be fully flexed, toes pointing up. Execute the movement by pressing downward through the balls of your feet as far as possible.','After a brief pause, reverse the motion and repeat.'], ARRAY['calves'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Calf Press On The Leg Press Machine', 'machine', true, 'machine', 'beginner', 'push', 'isolation', ARRAY['Using a leg press machine, sit down on the machine and place your legs on the platform directly in front of you at a medium (shoulder width) foot stance.','Lower the safety bars holding the weighted platform in place and press the platform all the way up until your legs are fully extended in front of you without locking your knees. (Note: In some leg press units you can leave the safety bars on for increased safety. If your leg press unit allows for this, then this is the preferred method of performing the exercise.) Your torso and the legs should make perfect 90-degree angle. Now carefully place your toes and balls of your feet on the lower portion of the platform with the heels extending off. Toes should be facing forward, outwards or inwards as described at the beginning of the chapter. This will be your starting position.','Press on the platform by raising your heels as you breathe out by extending your ankles as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending at any time. Hold the contracted position by a second before you start to go back down.','Go back slowly to the starting position as you breathe in by lowering your heels as you bend the ankles until calves are stretched.','Repeat for the recommended amount of repetitions.'], ARRAY['calves'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Calf Raise On A Dumbbell', 'dumbbell', true, 'dumbbell', 'intermediate', 'push', 'isolation', ARRAY['Hang on to a sturdy object for balance and stand on a dumbbell handle, preferably one with round plates so that it rolls as in this manner you have to work harder to stabilize yourself; thus increasing the effectiveness of the exercise.','Now roll your foot slightly forward so that you can get a nice stretch of the calf. This will be your starting position.','Lift the calf as you roll your foot over the top of the handle so that you get a full extension. Exhale during the execution of this movement. Contract the calf hard at the top and hold for a second. Tip: As you come up, roll the dumbbell slightly backward.','Now inhale as you roll the dumbbell slightly forward as you come down to get a better stretch.','Repeat for the recommended amount of repetitions.'], ARRAY['calves'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Calf Raises - With Bands', 'bands', true, 'bands', 'beginner', 'push', 'isolation', ARRAY['Grab an exercise band and stand on it with your toes making sure that the length of the band between the foot and the arms is the same for both sides.','While holding the handles of the band, raise the arms to the side of your head as if you were getting ready to perform a shoulder press. The palms should be facing forward with the elbows bent and to the sides. This movement will create tension on the band. This will be your starting position.','Keeping the hands by your shoulder, stand up on your toes as you exhale and contract the calves hard at the top of the movement.','After a one second contraction, slowly go back down to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['calves'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Car Deadlift', 'other', true, 'other', 'intermediate', 'pull', 'compound', ARRAY['This event apparatus typically has neutral grip handles, however some have a straight bar that you can approach like a normal deadlift. The apparatus can be loaded with a vehicle or other heavy objects such as tractor tires or kegs.','Center yourself between the handles if you are a strong squatter, or back a couple inches if you are a strong deadlifter. You feet should be about hip width apart. Bend at the hip to grip the handles. With your feet and your grip set, take a big breath and then lower your hips and flex the knees.','Look forward with your head, keep your chest up and your back arched, and begin driving through the heels to move the weight upward. As the weight comes up, pull your shoulder blades together as you drive your hips forward.','Lower the weight by bending at the hips and guiding it to the floor.'], ARRAY['quadriceps'], ARRAY['forearms','glutes','hamstrings','lower back','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Car Drivers', 'barbell', true, 'barbell', 'beginner', 'push', 'isolation', ARRAY['While standing upright, hold a barbell plate in both hands at the 3 and 9 o''clock positions. Your palms should be facing each other and your arms should be extended straight out in front of you. This will be your starting position.','Initiate the movement by rotating the plate as far to one side as possible. Use the same type of movement you would use to turn a steering wheel to one side.','Reverse the motion, turning it all the way to the opposite side.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Carioca Quick Step', 'body only', true, 'body only', 'beginner', NULL, NULL, ARRAY['Begin with your feet a few inches apart and your left arm up in a relaxed, athletic position.','With your right foot, quick step behind and pull the knee up.','Fire your arms back up when you pull the right knee, being sure that your knee goes straight up and down. Avoid turning your feet as you move and continue to look forward as you move to the side.'], ARRAY['adductors'], ARRAY['abdominals','abductors','calves','glutes','hamstrings','quadriceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Catch and Overhead Throw', 'medicine ball', true, 'medicine ball', 'beginner', 'push', 'compound', ARRAY['Begin standing while facing a wall or a partner.','Using both hands, position the ball behind your head, stretching as much as possible, and forcefully throw the ball forward.','Ensure that you follow your throw through, being prepared to receive your rebound from your throw. If you are throwing against the wall, make sure that you stand close enough to the wall to receive the rebound, and aim a little higher than you would with a partner.'], ARRAY['lats'], ARRAY['abdominals','chest','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Chain Handle Extension', 'other', true, 'other', 'intermediate', 'push', 'isolation', ARRAY['You will need two cable handle attachments and a flat bench, as well as chains, for this exercise. Clip the middle of the chains to the handles, and position yourself on the flat bench. Your elbows should be pointing straight up.','Begin by extending through the elbow, keeping your upper arm still, with your wrists pronated.','Pause at the lockout, and reverse the motion to return to the starting position.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Chain Press', 'other', true, 'other', 'intermediate', 'push', 'compound', ARRAY['Begin by connecting the chains to the cable handle attachments. Position yourself on the flat bench in the same position as for a dumbbell press. Your wrists should be pronated and arms perpendicular to the floor. This will be your starting position.','Lower the chains by flexing the elbows, unloading some of the chain onto the floor.','Continue until your elbow forms a 90 degree angle, and then reverse the motion by extending through the elbow to lockout.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Chair Squat', 'machine', true, 'machine', 'beginner', 'push', 'compound', ARRAY['To begin, first set the bar to a position that best matches your height. Once the bar is loaded, step under it and position it across the back of your shoulders.','Take the bar with your hands facing forward, unlock it and lift it off the rack by extending your legs.','Move your feet forward about 18 inches in front of the bar. Position your legs using a shoulder width stance with the toes slightly pointed out. Look forward at all times and maintain a neutral or slightly arched spine. This will be your starting position.','Slowly lower the bar by bending the knees as you maintain a straight posture with the head up. Continue down until the angle between the upper and lower leg breaks 90 degrees.','Begin to raise the bar as you exhale by pushing the floor with the heels of your feet, extending the knees and returning to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Chest Push from 3 point stance', 'medicine ball', true, 'medicine ball', 'beginner', 'push', 'compound', ARRAY['Begin in a three point stance, squatted down with your back flat and one hand on the ground. Place the medicine ball directly in front of you.','To begin, take your first step as you pull the ball to your chest, positioning both hands to prepare for the throw.','As you execute the second step, explosively release the ball forward as hard as possible.'], ARRAY['chest'], ARRAY['abdominals','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Chest Push (multiple response)', 'medicine ball', true, 'medicine ball', 'beginner', 'push', 'compound', ARRAY['Begin in a kneeling position facing a wall or utilize a partner. Hold the ball with both hands tight into the chest.','Execute the pass by exploding forward and outward with the hips while pushing the ball as hard as possible.','Follow through by falling forward, catching yourself with your hands.','Immediately return to an upright position. Repeat for the desired number of repetitions.'], ARRAY['chest'], ARRAY['abdominals','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Chest Push (single response)', 'medicine ball', true, 'medicine ball', 'beginner', 'push', 'compound', ARRAY['Begin in a kneeling position holding the medicine ball with both hands tightly into the chest.','Execute the pass by exploding forward and outward with the hips while pushing the ball as far as possible.','Follow through by falling forward, catching yourself with your hands.'], ARRAY['chest'], ARRAY['abdominals','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Chest Push with Run Release', 'medicine ball', true, 'medicine ball', 'beginner', 'push', 'compound', ARRAY['Begin in an athletic stance with the knees bent, hips back, and back flat. Hold the medicine ball near your legs. This will be your starting position.','While taking your first step draw the medicine ball into your chest.','As you take the second step, explosively push the ball forward, immediately sprinting for 10 yards after the release. If you are really fast, you can catch your own pass!'], ARRAY['chest'], ARRAY['abdominals','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Chin-Up', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Grab the pull-up bar with the palms facing your torso and a grip closer than the shoulder width.','As you have both arms extended in front of you holding the bar at the chosen grip width, keep your torso as straight as possible while creating a curvature on your lower back and sticking your chest out. This is your starting position. Tip: Keeping the torso as straight as possible maximizes biceps stimulation while minimizing back involvement.','As you breathe out, pull your torso up until your head is around the level of the pull-up bar. Concentrate on using the biceps muscles in order to perform the movement. Keep the elbows close to your body. Tip: The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.','After a second of squeezing the biceps in the contracted position, slowly lower your torso back to the starting position; when your arms are fully extended. Breathe in as you perform this portion of the movement.','Repeat this motion for the prescribed amount of repetitions.'], ARRAY['lats'], ARRAY['biceps','forearms','middle back'], ARRAY['Palms facing you, shoulder width grip','Easier than pullups, great for building up','Pull until chin clears bar','Squeeze biceps and lats at top','Lower to full dead hang every rep'], ARRAY['Partial range of motion','Using momentum','Grip too wide (becomes a pullup)'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Circus Bell', 'other', true, 'other', 'expert', 'push', 'compound', ARRAY['The circus bell is an oversized dumbbell with a thick handle. Begin with the dumbbell between your feet, and grip the handle with both hands.','Clean the dumbbell by extending through your hips and knees to deliver the implement to the desired shoulder, letting go with the extra hand.','Ensure that you get one of the dumbbell heads behind the shoulder to keep from being thrown off balance. To raise it overhead, dip by flexing the knees, and the drive upwards as you extend the dumbbell overhead, leaning slightly away from it as you do so.','Carefully guide the bell back to the floor, keeping it under control as much as possible. It is best to perform this event on a thick rubber mat to prevent damage to the floor.'], ARRAY['shoulders'], ARRAY['forearms','glutes','hamstrings','lower back','traps','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Clean', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['With a barbell on the floor close to the shins, take an overhand (or hook) grip just outside the legs. Lower your hips with the weight focused on the heels, back straight, head facing forward, chest up, with your shoulders just in front of the bar. This will be your starting position.','','Begin the first pull by driving through the heels, extending your knees. Your back angle should stay the same, and your arms should remain straight. Move the weight with control as you continue to above the knees.','Next comes the second pull, the main source of acceleration for the clean. As the bar approaches the mid-thigh position, begin extending through the hips. In a jumping motion, accelerate by extending the hips, knees, and ankles, using speed to move the bar upward. There should be no need to actively pull through the arms to accelerate the weight; at the end of the second pull, the body should be fully extended, leaning slightly back, with the arms still extended.','As full extension is achieved, transition into the third pull by aggressively shrugging and flexing the arms with the elbows up and out. At peak extension, aggressively pull yourself down, rotating your elbows under the bar as you do so. Receive the bar in a front squat position, the depth of which is dependent upon the height of the bar at the end of the third pull. The bar should be racked onto the protracted shoulders, lightly touching the throat with the hands relaxed. Continue to descend to the bottom squat position, which will help in the recovery.','Immediately recover by driving through the heels, keeping the torso upright and elbows up. Continue until you have risen to a standing position.'], ARRAY['hamstrings'], ARRAY['calves','forearms','glutes','lower back','quadriceps','shoulders','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Clean Deadlift', 'barbell', true, 'barbell', 'beginner', 'pull', 'compound', ARRAY['Begin standing with a barbell close to your shins. Your feet should be directly under your hips with your feet turned out slightly. Grip the bar with a double overhand grip or hook grip, about shoulder width apart. Squat down to the bar. Your spine should be in full extension, with a back angle that places your shoulders in front of the bar and your back as vertical as possible.','Begin by driving through the floor through the front of your heels. As the bar travels upward, maintain a constant back angle. Flare your knees out to the side to help keep them out of the bar''s path.','After the bar crosses the knees, complete the lift by driving the hips into the bar until your hips and knees are extended.'], ARRAY['hamstrings'], ARRAY['forearms','glutes','lower back','middle back','quadriceps','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Clean Pull', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['With a barbell on the floor close to the shins, take an overhand or hook grip just outside the legs. Lower your hips with the weight focused on the heels, back straight, head facing forward, chest up, with your shoulders just in front of the bar. This will be your starting position.','Begin the first pull by driving through the heels, extending your knees. Your back angle should stay the same, and your arms should remain straight and elbows out. Move the weight with control as you continue to above the knees.','Next comes the second pull, the main source of acceleration for the clean. As the bar approaches the mid-thigh position, begin extending through the hips. In a jumping motion, accelerate by extending the hips, knees, and ankles, using speed to move the bar upward. There should be no need to actively pull through the arms to accelerate the weight; at the end of the second pull, the body should be fully extended, leaning slightly back, with the arms still extended. Full extension should be violent and abrupt, and ensure that you do not prolong the extension for longer than necessary.'], ARRAY['quadriceps'], ARRAY['forearms','glutes','hamstrings','lower back','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Clean Shrug', 'barbell', true, 'barbell', 'beginner', 'pull', 'compound', ARRAY['Begin with a shoulder width, double overhand or hook grip, with the bar hanging at the mid thigh position. Your back should be straight and inclined slightly forward.','Shrug your shoulders towards your ears. While this exercise can usually by loaded with heavier weight than a clean, avoid overloading to the point that the execution slows down.'], ARRAY['traps'], ARRAY['forearms','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Clean and Jerk', 'barbell', true, 'barbell', 'expert', 'push', 'compound', ARRAY['With a barbell on the floor close to the shins, take an overhand or hook grip just outside the legs. Lower your hips with the weight focused on the heels, back straight, head facing forward, chest up, with your shoulders just in front of the bar. This will be your starting position.','Begin the first pull by driving through the heels, extending your knees. Your back angle should stay the same, and your arms should remain straight. Move the weight with control as you continue to above the knees.','Next comes the second pull, the main source of acceleration for the clean. As the bar approaches the mid-thigh position, begin extending through the hips. In a jumping motion, accelerate by extending the hips, knees, and ankles, using speed to move the bar upward. There should be no need to actively pull through the arms to accelerate the weight; at the end of the second pull, the body should be fully extended, leaning slightly back, with the arms still extended.','As full extension is achieved, transition into the third pull by aggressively shrugging and flexing the arms with the elbows up and out. At peak extension, aggressively pull yourself down, rotating your elbows under the bar as you do so. Receive the bar in a front squat position, the depth of which is dependent upon the height of the bar at the end of the third pull. The bar should be racked onto the protracted shoulders, lightly touching the throat with the hands relaxed. Continue to descend to the bottom squat position, which will help in the recovery.','Immediately recover by driving through the heels, keeping the torso upright and elbows up. Continue until you have risen to a standing position.','The second phase is the jerk, which raises the weight overhead. Standing with the weight racked on the front of the shoulders, begin with the dip. With your feet directly under your hips, flex the knees without moving the hips backward. Go down only slightly, and reverse direction as powerfully as possible.','Drive through the heels create as much speed and force as possible, and be sure to move your head out of the way as the bar leaves the shoulders.','At this moment as the feet leave the floor, the feet must be placed into the receiving position as quickly as possible. In the brief moment the feet are not actively driving against the platform, the athletes effort to push the bar up will drive them down. The feet should be split, with one foot forward, and one foot back. Receive the bar with the arms locked out overhead. Return to a standing position.'], ARRAY['shoulders'], ARRAY['abdominals','glutes','hamstrings','lower back','quadriceps','traps','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Clean and Press', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Assume a shoulder-width stance, with knees inside the arms. Now while keeping the back flat, bend at the knees and hips so that you can grab the bar with the arms fully extended and a pronated grip that is slightly wider than shoulder width. Point the elbows out to sides. The bar should be close to the shins. Position the shoulders over or slightly ahead of the bar. Establish a flat back posture. This will be your starting position.','Begin to pull the bar by extending the knees. Move your hips forward and raise the shoulders at the same rate while keeping the angle of the back constant; continue to lift the bar straight up while keeping it close to your body.','As the bar passes the knee, extend at the ankles, knees, and hips forcefully, similar to a jumping motion. As you do so, continue to guide the bar with your hands, shrugging your shoulders and using the momentum from your movement to pull the bar as high as possible. The bar should travel close to your body, and you should keep your elbows out.','At maximum elevation, your feet should clear the floor and you should start to pull yourself under the bar. The mechanics of this could change slightly, depending on the weight used. You should descend into a squatting position as you pull yourself under the bar.','As the bar hits terminal height, rotate your elbows around and under the bar. Rack the bar across the front of the shoulders while keeping the torso erect and flexing the hips and knees to absorb the weight of the bar.','Stand to full height, holding the bar in the clean position.','Without moving your feet, press the bar overhead as you exhale. Lower the bar under control .'], ARRAY['shoulders'], ARRAY['abdominals','calves','glutes','hamstrings','lower back','middle back','quadriceps','shoulders','traps','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Clean from Blocks', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['With a barbell on boxes or stands of the desired height, take an overhand or hook grip just outside the legs. Lower your hips with the weight focused on the heels, back straight, head facing forward, chest up, with your shoulders just in front of the bar. This will be your starting position.','Begin the first pull by driving through the heels, extending your knees. Your back angle should stay the same, and your arms should remain straight with the elbows pointed out.','As full extension is achieved, transition into the receiving position by aggressively shrugging and flexing the arms with the elbows up and out. Aggressively pull yourself down, rotating your elbows under the bar as you do so. Receive the bar in a front squat position, the depth of which is dependent upon the height of the bar at the end of the third pull. The bar should be racked onto the protracted shoulders, lightly touching the throat with the hands relaxed. Continue to descend to the bottom squat position, which will help in the recovery.','Immediately recover by driving through the heels, keeping the torso upright and elbows up. Continue until you have risen to a standing position. Return the weight to the boxes for the next rep.'], ARRAY['quadriceps'], ARRAY['calves','glutes','hamstrings','shoulders','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Clock Push-Up', 'body only', true, 'body only', 'intermediate', 'push', 'compound', ARRAY['Move into a prone position on the floor, supporting your weight on your hands and toes.','Your arms should be fully extended with the hands around shoulder width. Keep your body straight throughout the movement. This will be your starting position.','Descend by flexing at the elbow, lowering your chest toward the ground.','At the bottom, reverse the motion by pushing yourself up through elbow extension as quickly as possible until you are air borne. Aim to jump 12-18 inches to one side.','As you accelerate up, move your outside foot away from your direction of travel. Leaving the ground, shift your body about 30 degrees for the next repetition.','Return to the starting position and repeat the exercise, working all the way around until you are back where you started.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Close-Grip Barbell Bench Press', 'barbell', true, 'barbell', 'beginner', 'push', 'compound', ARRAY['Lie back on a flat bench. Using a close grip (around shoulder width), lift the bar from the rack and hold it straight over you with your arms locked. This will be your starting position.','As you breathe in, come down slowly until you feel the bar on your middle chest. Tip: Make sure that - as opposed to a regular bench press - you keep the elbows close to the torso at all times in order to maximize triceps involvement.','After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your triceps muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up.','Repeat the movement for the prescribed amount of repetitions.','When you are done, place the bar back in the rack.'], ARRAY['triceps'], ARRAY['chest','shoulders'], ARRAY['Hands shoulder width or slightly narrower','Keep elbows tucked close to body','Lower bar to lower chest','Focus on squeezing triceps at lockout','One of the best tricep mass builders'], ARRAY['Grip too narrow causing wrist pain','Flaring elbows out wide','Not locking out'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Close-Grip Dumbbell Press', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Place a dumbbell standing up on a flat bench.','Ensuring that the dumbbell stays securely placed at the top of the bench, lie perpendicular to the bench with only your shoulders lying on the surface. Hips should be below the bench and your legs bent with your feet firmly on the floor.','Grasp the dumbbell with both hands and hold it straight over your chest at arm''s length. Both palms should be pressing against the underside of the sides of the dumbbell. This will be your starting position.','Initiate the movement by lowering the dumbbell to your chest.','Return to the starting position by extending the elbows.'], ARRAY['triceps'], ARRAY['chest','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Close-Grip EZ-Bar Curl with Band', 'e-z curl bar', true, 'e-z curl bar', 'beginner', 'pull', 'isolation', ARRAY['Attach a band to each end of the bar. Take the bar, placing a foot on the middle of the band. Stand upright with a narrow, supinated grip on the EZ bar. The elbows should be close to the torso. This will be your starting position.','While keeping the upper arms in place, flex the elbows to execute the curl. Exhale as the weight is lifted.','Continue the movement until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a second and squeeze the biceps hard.','Slowly begin to bring the bar back to starting position as your breathe in.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Close-Grip EZ-Bar Press', 'e-z curl bar', true, 'e-z curl bar', 'beginner', 'push', 'compound', ARRAY['Lie on a flat bench with an EZ bar loaded to an appropriate weight.','Using a narrow grip lift the bar and hold it straight over your torso with your elbows in. The arms should be perpendicular to the floor. This will be your starting position.','Now lower the bar down to your lower chest as you breathe in. Keep the elbows in as you perform this movement.','Using the triceps to push the bar back up, press it back to the starting position by extending the elbows as you exhale.','Repeat.'], ARRAY['triceps'], ARRAY['chest','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Close-Grip EZ Bar Curl', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Stand up with your torso upright while holding an E-Z Curl Bar at the closer inner handle. The palm of your hands should be facing forward and they should be slightly tilted inwards due to the shape of the bar. The elbows should be close to the torso. This will be your starting position.','While holding the upper arms stationary, curl the weights forward while contracting the biceps as you breathe out. Tip: Only the forearms should move.','Continue the movement until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a second and squeeze the biceps hard.','Slowly begin to bring the bar back to starting position as your breathe in.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Close-Grip Front Lat Pulldown', 'cable', true, 'cable', 'beginner', 'pull', 'compound', ARRAY['Sit down on a pull-down machine with a wide bar attached to the top pulley. Make sure that you adjust the knee pad of the machine to fit your height. These pads will prevent your body from being raised by the resistance attached to the bar.','Grab the bar with the palms facing forward using the prescribed grip. Note on grips: For a wide grip, your hands need to be spaced out at a distance wider than your shoulder width. For a medium grip, your hands need to be spaced out at a distance equal to your shoulder width and for a close grip at a distance smaller than your shoulder width.','As you have both arms extended in front of you - while holding the bar at the chosen grip width - bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.','As you breathe out, bring the bar down until it touches your upper chest by drawing the shoulders and the upper arms down and back. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary (only the arms should move). The forearms should do no other work except for holding the bar; therefore do not try to pull the bar down using the forearms.','After a second in the contracted position, while squeezing your shoulder blades together, slowly raise the bar back to the starting position when your arms are fully extended and the lats are fully stretched. Inhale during this portion of the movement.','6. Repeat this motion for the prescribed amount of repetitions.'], ARRAY['lats'], ARRAY['biceps','middle back','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Close-Grip Push-Up off of a Dumbbell', 'body only', true, 'body only', 'intermediate', 'push', 'compound', ARRAY['Lie on the floor and place your hands on an upright dumbbell. Supporting your weight on your toes and hands, keep your torso rigid and your elbows in with your arms straight. This will be your starting position.','Lower your body, allowing the elbows to flex while you inhale. Keep your body straight, not allowing your hips to rise or sag.','Press yourself back up to the starting position by extending the elbows. Breathe out as you perform this step.','After a pause at the contracted position, repeat the movement for the prescribed amount of repetitions.'], ARRAY['triceps'], ARRAY['abdominals','chest','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Close-Grip Standing Barbell Curl', 'barbell', true, 'barbell', 'beginner', 'pull', 'isolation', ARRAY['Hold a barbell with both hands, palms up and a few inches apart.','Stand with your torso straight and your head up. Your feet should be about shoulder width and your elbows close to your torso. This will be your starting position. Tip: You will keep your upper arms and elbows stationary throughout the movement.','Curl the bar up in a semicircular motion until the forearms touch your biceps. Exhale as you perform this portion of the movement and contract your biceps hard for a second at the top. Tip: Avoid bending the back or using swinging motions as you lift the weight. Only the forearms should move.','Slowly go back down to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cocoons', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Begin by lying on your back on the ground. Your legs should be straight and your arms extended behind your head. This will be your starting position.','To perform the movement, tuck the knees toward your chest, rotating your pelvis to lift your glutes from the floor. As you do so, flex the spine, bringing your arms back over your head to perform a simultaneous crunch motion.','After a brief pause, return to the starting position.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Conan''s Wheel', 'other', true, 'other', 'intermediate', NULL, 'compound', ARRAY['With the weight loaded, take a zurcher hold on the end of the implement. Place the bar in the crook of the elbow and hold onto your wrist. Try to keep the weight off of the forearms.','Begin by lifting the weight from the ground. Keep a tight, upright posture as you being to walk, taking short, fast steps. Look up and away as you turn in a circle. Do not hold your breath during the event. Continue walking until you complete one or more complete turns.'], ARRAY['quadriceps'], ARRAY['abdominals','biceps','calves','forearms','lower back','shoulders','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Concentration Curls', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Sit down on a flat bench with one dumbbell in front of you between your legs. Your legs should be spread with your knees bent and feet on the floor.','Use your right arm to pick the dumbbell up. Place the back of your right upper arm on the top of your inner right thigh. Rotate the palm of your hand until it is facing forward away from your thigh. Tip: Your arm should be extended and the dumbbell should be above the floor. This will be your starting position.','While holding the upper arm stationary, curl the weights forward while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Tip: At the top of the movement make sure that the little finger of your arm is higher than your thumb. This guarantees a good contraction. Hold the contracted position for a second as you squeeze the biceps.','Slowly begin to bring the dumbbells back to starting position as your breathe in. Caution: Avoid swinging motions at any time.','Repeat for the recommended amount of repetitions. Then repeat the movement with the left arm.'], ARRAY['biceps'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cross-Body Crunch', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Lie flat on your back and bend your knees about 60 degrees.','Keep your feet flat on the floor and place your hands loosely behind your head. This will be your starting position.','Now curl up and bring your right elbow and shoulder across your body while bring your left knee in toward your left shoulder at the same time. Reach with your elbow and try to touch your knee. Exhale as you perform this movement. Tip: Try to bring your shoulder up towards your knee rather than just your elbow and remember that the key is to contract the abs as you perform the movement; not just to move the elbow.','Now go back down to the starting position as you inhale and repeat with the left elbow and the right knee.','Continue alternating in this manner until all prescribed repetitions are done.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cross Body Hammer Curl', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Stand up straight with a dumbbell in each hand. Your hands should be down at your side with your palms facing in.','While keeping your palms facing in and without twisting your arm, curl the dumbbell of the right arm up towards your left shoulder as you exhale. Touch the top of the dumbbell to your shoulder and hold the contraction for a second.','Slowly lower the dumbbell along the same path as you inhale and then repeat the same movement for the left arm.','Continue alternating in this fashion until the recommended amount of repetitions is performed for each arm.'], ARRAY['biceps'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cross Over - With Bands', 'bands', true, 'bands', 'beginner', 'push', 'compound', ARRAY['Secure an exercise band around a stationary post.','While facing away from the post, grab the handles on both ends of the band and step forward enough to create tension on the band.','Raise your arms to the sides, parallel to the floor, perpendicular to your torso (your torso and the arms should resemble the letter T) and with the palms facing forward. Have them extended with a slight bend at the elbows. This will be your starting position.','While keeping your arms straight, bring them across your chest in a semicircular motion to the front as you exhale and flex your pecs. Hold the contraction for a second.','Slowly return to the starting position as you inhale.','Perform for the recommended amount of repetitions.'], ARRAY['chest'], ARRAY['biceps','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Crucifix', 'other', true, 'other', 'beginner', 'static', 'isolation', ARRAY['In the crucifix, you statically hold weights out to the side for time. While the event can be practiced using dumbbells, it is best to practice with one of the various implements used, such as axes and hammers, as it feels different.','Begin standing, and raise your arms out to the side holding the implements. Your arms should be parallel to the ground. In competition, judges or sensors are used to let you know when you break parallel. Hold for as long as you can. Typically, the weights should be heavy enough that you fail in 30-60 seconds.'], ARRAY['shoulders'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Crunch - Hands Overhead', 'body only', true, 'body only', 'beginner', 'pull', 'isolation', ARRAY['Lie on the floor with your back flat and knees bent with around a 60-degree angle between the hamstrings and the calves.','Keep your feet flat on the floor and stretch your arms overhead with your palms crossed. This will be your starting position.','Curl your upper body forward and bring your shoulder blades just off the floor. At all times, keep your arms aligned with your head, neck and shoulder. Don''t move them forward from that position. Exhale as you perform this portion of the movement and hold the contraction for a second.','Slowly lower down to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Crunch - Legs On Exercise Ball', 'body only', true, 'body only', 'beginner', 'pull', 'isolation', ARRAY['Lie flat on your back with your feet resting on an exercise ball and your knees bent at a 90 degree angle.','Place your feet three to four inches apart and point your toes inward so they touch.','Place your hands lightly on either side of your head keeping your elbows in. Tip: Don''t lock your fingers behind your head.','Push the small of your back down in the floor in order to better isolate your abdominal muscles. This will be your starting position.','Begin to roll your shoulders off the floor and continue to push down as hard as you can with your lower back. Your shoulders should come up off the floor only about four inches, and your lower back should remain on the floor. Breathe out as you execute this portion of the movement. Squeeze your abdominals hard at the top of the contraction and hold for a second. Tip: Focus on a slow, controlled movement. Refrain from using momentum at any time.','Slowly go back down to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Crunches', 'body only', true, 'body only', 'beginner', 'pull', 'isolation', ARRAY['Lie flat on your back with your feet flat on the ground, or resting on a bench with your knees bent at a 90 degree angle. If you are resting your feet on a bench, place them three to four inches apart and point your toes inward so they touch.','Now place your hands lightly on either side of your head keeping your elbows in. Tip: Don''t lock your fingers behind your head.','While pushing the small of your back down in the floor to better isolate your abdominal muscles, begin to roll your shoulders off the floor.','Continue to push down as hard as you can with your lower back as you contract your abdominals and exhale. Your shoulders should come up off the floor only about four inches, and your lower back should remain on the floor. At the top of the movement, contract your abdominals hard and keep the contraction for a second. Tip: Focus on slow, controlled movement - don''t cheat yourself by using momentum.','After the one second contraction, begin to come down slowly again to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Cuban Press', 'dumbbell', true, 'dumbbell', 'intermediate', 'push', 'compound', ARRAY['Take a dumbbell in each hand with a pronated grip in a standing position. Raise your upper arms so that they are parallel to the floor, allowing your lower arms to hang in the scarecrow position. This will be your starting position.','To initiate the movement, externally rotate the shoulders to move the upper arm 180 degrees. Keep the upper arms in place, rotating the upper arms until the wrists are directly above the elbows, the forearms perpendicular to the floor.','Now press the dumbbells by extending at the elbows, straightening your arms overhead.','Return to the starting position as you breathe in by reversing the steps.','Repeat for the recommended amount of repetitions.'], ARRAY['shoulders'], ARRAY['traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dead Bug', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Begin lying on your back with your hands extended above you toward the ceiling.','Bring your feet, knees, and hips up to 90 degrees.','Exhale hard to bring your ribcage down and flatten your back onto the floor, rotating your pelvis up and squeezing your glutes. Hold this position throughout the movement. This will be your starting position.','Initiate the exercise by extending one leg, straightening the knee and hip to bring the leg just above the ground.','Maintain the position of your lumbar and pelvis as you perform the movement, as your back is going to want to arch.','Stay tight and return the working leg to the starting position.','Repeat on the opposite side, alternating until the set is complete.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY['Lower back pressed into floor the entire time','Opposite arm and leg extend together','Move slowly and with control','Exhale as you extend, inhale as you return','The #1 core stability exercise for beginners'], ARRAY['Lower back arching off floor','Moving too fast','Holding breath'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Deadlift with Bands', 'barbell', true, 'barbell', 'expert', 'pull', 'compound', ARRAY['To deadlift with short bands, simply loop them over the bar before you start, and step into them to set up. For long bands, they will need to be anchored to a secure base, such as heavy dumbbells or a rack.','With your feet, and your grip set, take a big breath and then lower your hips and bend the knees until your shins contact the bar. Look forward with your head, keep your chest up and your back arched, and begin driving through the heels to move the weight upward. After the bar passes the knees, aggressively pull the bar back, pulling your shoulder blades together as you drive your hips forward into the bar.','Lower the bar by bending at the hips and guiding it to the floor.'], ARRAY['lower back'], ARRAY['forearms','glutes','hamstrings','middle back','quadriceps','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Deadlift with Chains', 'barbell', true, 'barbell', 'expert', 'pull', 'compound', ARRAY['You can attach the chains to the sleeves of the bar, or just drape the middle over the bar so there is a greater weight increase as you lift.','Approach the bar so that it is centered over your feet. You feet should be about hip width apart. Bend at the hip to grip the bar at shoulder width, allowing your shoulder blades to protract. Typically, you would use an overhand grip or an over/under grip on heavier sets. With your feet, and your grip set, take a big breath and then lower your hips and bend the knees until your shins contact the bar.','Look forward with your head, keep your chest up and your back arched, and begin driving through the heels to move the weight upward. After the bar passes the knees, aggressively pull the bar back, pulling your shoulder blades together as you drive your hips forward into the bar.','Lower the bar by bending at the hips and guiding it to the floor.'], ARRAY['lower back'], ARRAY['forearms','glutes','hamstrings','middle back','quadriceps','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Decline Barbell Bench Press', 'barbell', true, 'barbell', 'beginner', 'push', 'compound', ARRAY['Secure your legs at the end of the decline bench and slowly lay down on the bench.','Using a medium width grip (a grip that creates a 90-degree angle in the middle of the movement between the forearms and the upper arms), lift the bar from the rack and hold it straight over you with your arms locked. The arms should be perpendicular to the floor. This will be your starting position. Tip: In order to protect your rotator cuff, it is best if you have a spotter help you lift the barbell off the rack.','As you breathe in, come down slowly until you feel the bar on your lower chest.','After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your chest muscles. Lock your arms and squeeze your chest in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up).','Repeat the movement for the prescribed amount of repetitions.','When you are done, place the bar back in the rack.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Decline Close-Grip Bench To Skull Crusher', 'barbell', true, 'barbell', 'intermediate', 'push', 'compound', ARRAY['Secure your legs at the end of the decline bench and slowly lay down on the bench.','Using a close grip (a grip that is slightly less than shoulder width), lift the bar from the rack and hold it straight over you with your arms locked and elbows in. The arms should be perpendicular to the floor. This will be your starting position. Tip: In order to protect your rotator cuff, it is best if you have a spotter help you lift the barbell off the rack.','Now lower the bar down to your lower chest as you breathe in. Keep the elbows in as you perform this movement.','Using the triceps to push the bar back up, press it back to the starting position as you exhale.','As you breathe in and you keep the upper arms stationary, bring the bar down slowly by moving your forearms in a semicircular motion towards you until you feel the bar slightly touch your forehead. Breathe in as you perform this portion of the movement.','Lift the bar back to the starting position by contracting the triceps and exhaling.','Repeat steps 3-6 until the recommended amount of repetitions is performed.'], ARRAY['triceps'], ARRAY['chest','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Decline Crunch', 'body only', true, 'body only', 'intermediate', 'pull', 'isolation', ARRAY['Secure your legs at the end of the decline bench and lie down.','Now place your hands lightly on either side of your head keeping your elbows in. Tip: Don''t lock your fingers behind your head.','While pushing the small of your back down in the bench to better isolate your abdominal muscles, begin to roll your shoulders off it.','Continue to push down as hard as you can with your lower back as you contract your abdominals and exhale. Your shoulders should come up off the bench only about four inches, and your lower back should remain on the bench. At the top of the movement, contract your abdominals hard and keep the contraction for a second. Tip: Focus on slow, controlled movement - don''t cheat yourself by using momentum.','After the one second contraction, begin to come down slowly again to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Decline Dumbbell Bench Press', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Secure your legs at the end of the decline bench and lie down with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.','Once you are laying down, move the dumbbells in front of you at shoulder width.','Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.','Bring down the weights slowly to your side as you breathe out. Keep full control of the dumbbells at all times. Tip: Throughout the motion, the forearms should always be perpendicular to the floor.','As you breathe out, push the dumbbells up using your pectoral muscles. Lock your arms in the contracted position, squeeze your chest, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up..','Repeat the movement for the prescribed amount of repetitions of your training program.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Decline Dumbbell Flyes', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Secure your legs at the end of the decline bench and lie down with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.','Once you are laying down, move the dumbbells in front of you at shoulder width. The palms of the hands should be facing each other and the arms should be perpendicular to the floor and fully extended. This will be your starting position.','With a slight bend on your elbows in order to prevent stress at the biceps tendon, lower your arms out at both sides in a wide arc until you feel a stretch on your chest. Breathe in as you perform this portion of the movement. Tip: Keep in mind that throughout the movement, the arms should remain stationary; the movement should only occur at the shoulder joint.','Return your arms back to the starting position as you squeeze your chest muscles and breathe out. Tip: Make sure to use the same arc of motion used to lower the weights.','Hold for a second at the contracted position and repeat the movement for the prescribed amount of repetitions.'], ARRAY['chest'], ARRAY[]::TEXT[], ARRAY['Slight bend in elbows throughout','Open arms wide like hugging a tree in reverse','Feel the stretch across chest at bottom','Squeeze chest to bring dumbbells together','Control the descent, dont just drop arms'], ARRAY['Straightening arms (turns into a press)','Going too heavy and losing form','Not feeling it in chest'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Decline Dumbbell Triceps Extension', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'isolation', ARRAY['Secure your legs at the end of the decline bench and lie down with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.','Once you are laying down, move the dumbbells in front of you at shoulder width. The palms of the hands should be facing each other and the arms should be perpendicular to the floor and fully extended. This will be your starting position.','As you breathe in and you keep the upper arms stationary (and elbows in), bring the dumbbells down slowly by moving your forearms in a semicircular motion towards you until your thumbs are next to your ears. Breathe in as you perform this portion of the movement.','Lift the dumbbells back to the starting position by contracting the triceps and exhaling.','Repeat for the recommended amount of repetitions.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Decline EZ Bar Triceps Extension', 'barbell', true, 'barbell', 'beginner', 'push', 'isolation', ARRAY['Secure your legs at the end of the decline bench and slowly lay down on the bench.','Using a close grip (a grip that is slightly less than shoulder width), lift the EZ bar from the rack and hold it straight over you with your arms locked and elbows in. The arms should be perpendicular to the floor. This will be your starting position. Tip: In order to protect your rotator cuff, it is best if you have a spotter help you lift the barbell off the rack.','As you breathe in and you keep the upper arms stationary, bring the bar down slowly by moving your forearms in a semicircular motion towards you until you feel the bar slightly touch your forehead. Breathe in as you perform this portion of the movement.','Lift the bar back to the starting position by contracting the triceps and exhaling.','Repeat until the recommended amount of repetitions is performed.'], ARRAY['triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Decline Oblique Crunch', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Secure your legs at the end of the decline bench and slowly lay down on the bench.','Raise your upper body off the bench until your torso is about 35-45 degrees if measured from the floor.','Put one hand beside your head and the other on your thigh. This will be your starting position.','Raise your upper body slowly from the starting position while turning your torso to the left. Continue crunching up as you exhale until your right elbow touches your left knee. Hold this contracted position for a second. Tip: Focus on keeping your abs tight and keeping the movement slow and controlled.','Lower your body back down slowly to the starting position as you inhale.','After completing one set on the right for the recommended amount of repetitions, switch to your left side. Tip: Focus on really twisting your torso and feeling the contraction when you are in the up position.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Decline Push-Up', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['Lie on the floor face down and place your hands about 36 inches apart while holding your torso up at arms length. Move your feet up to a box or bench. This will be your starting position.','Next, lower yourself downward until your chest almost touches the floor as you inhale.','Now breathe out and press your upper body back up to the starting position while squeezing your chest.','After a brief pause at the top contracted position, you can begin to lower yourself downward again for as many repetitions as needed.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY['Feet elevated on bench or box','Hands shoulder width, fingers forward','Lower chest toward floor between hands','Push up explosively','Targets upper chest more than regular pushups'], ARRAY['Sagging hips','Not going deep enough','Flaring elbows too wide'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Decline Reverse Crunch', 'body only', true, 'body only', 'beginner', 'pull', 'compound', ARRAY['Lie on your back on a decline bench and hold on to the top of the bench with both hands. Don''t let your body slip down from this position.','Hold your legs parallel to the floor using your abs to hold them there while keeping your knees and feet together. Tip: Your legs should be fully extended with a slight bend on the knee. This will be your starting position.','While exhaling, move your legs towards the torso as you roll your pelvis backwards and you raise your hips off the bench. At the end of this movement your knees will be touching your chest.','Hold the contraction for a second and move your legs back to the starting position while inhaling.','Repeat for the recommended amount of repetitions.'], ARRAY['abdominals'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Decline Smith Press', 'machine', true, 'machine', 'beginner', 'push', 'compound', ARRAY['Place a decline bench underneath the Smith machine. Now place the barbell at a height that you can reach when lying down and your arms are almost fully extended. Using a pronated grip that is wider than shoulder width, unlock the bar from the rack and hold it straight over you with your arms extended. This will be your starting position.','As you inhale, lower the bar under control by allowing the elbows to flex, lightly contacting the torso.','After a brief pause, bring the bar back to the starting position by extending the elbows, exhaling as you do so.','Repeat the movement for the prescribed amount of repetitions.','When the set is complete, lock the bar back in the rack.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Deficit Deadlift', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Begin by having a platform or weight plates that you can stand on, usually 1-3 inches in height. Approach the bar so that it is centered over your feet. You feet should be about hip width apart. Bend at the hip to grip the bar at shoulder width, allowing your shoulder blades to protract. Typically, you would use an overhand grip or an over/under grip on heavier sets.','With your feet, and your grip set, take a big breath and then lower your hips and bend the knees until your shins contact the bar. Look forward with your head, keep your chest up and your back arched, and begin driving through the heels to move the weight upward. After the bar passes the knees, aggressively pull the bar back, pulling your shoulder blades together as you drive your hips forward into the bar.','Lower the bar by bending at the hips and guiding it to the floor.'], ARRAY['lower back'], ARRAY['forearms','glutes','hamstrings','middle back','quadriceps','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Depth Jump Leap', 'other', true, 'other', 'beginner', 'push', 'compound', ARRAY['For this drill you will need two boxes or benches, one 12 to 16 inches high and the other 22 to 26 inches high.','Stand on one of the two boxes with arms at the sides; feet should be together and slightly off the edge as in the depth jump. Place the other box approximately two or three feet in front of and facing the performer.','Begin by dropping off the initial box, landing and simultaneously taking off with both feet.','Rebound by driving upward and outward as intensely as possible, using the arms and full extension of the body to jump onto the higher box. Again, allow the legs to absorb the impact.'], ARRAY['quadriceps'], ARRAY['abductors','adductors','calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dip Machine', 'machine', true, 'machine', 'beginner', 'push', 'compound', ARRAY['Sit securely in a dip machine, select the weight and firmly grasp the handles.','Now keep your elbows in at your sides in order to place emphasis on the triceps. The elbows should be bent at a 90 degree angle.','As you contract the triceps, extend your arms downwards as you exhale. Tip: At the bottom of the movement, focus on keeping a little bend in your arms to keep tension on the triceps muscle.','Now slowly let your arms come back up to the starting position as you inhale.','Repeat for the recommended amount of repetitions.'], ARRAY['triceps'], ARRAY['chest','shoulders'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dips - Chest Version', 'other', true, 'other', 'intermediate', 'push', 'compound', ARRAY['For this exercise you will need access to parallel bars. To get yourself into the starting position, hold your body at arms length (arms locked) above the bars.','While breathing in, lower yourself slowly with your torso leaning forward around 30 degrees or so and your elbows flared out slightly until you feel a slight stretch in the chest.','Once you feel the stretch, use your chest to bring your body back to the starting position as you breathe out. Tip: Remember to squeeze the chest at the top of the movement for a second.','Repeat the movement for the prescribed amount of repetitions.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dips - Triceps Version', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['To get into the starting position, hold your body at arm''s length with your arms nearly locked above the bars.','Now, inhale and slowly lower yourself downward. Your torso should remain upright and your elbows should stay close to your body. This helps to better focus on tricep involvement. Lower yourself until there is a 90 degree angle formed between the upper arm and forearm.','Then, exhale and push your torso back up using your triceps to bring your body back to the starting position.','Repeat the movement for the prescribed amount of repetitions.'], ARRAY['triceps'], ARRAY['chest','shoulders'], ARRAY['Keep torso upright, dont lean forward','Lower until upper arms parallel to floor','Press up by straightening arms fully','Elbows point straight back not out','Lean forward = more chest, upright = more triceps'], ARRAY['Going too deep and straining shoulders','Leaning too far forward','Partial reps'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Donkey Calf Raises', 'other', true, 'other', 'intermediate', 'push', 'isolation', ARRAY['For this exercise you will need access to a donkey calf raise machine. Start by positioning your lower back and hips under the padded lever provided. The tailbone area should be the one making contact with the pad.','Place both of your arms on the side handles and place the balls of your feet on the calf block with the heels extending off. Align the toes forward, inward or outward, depending on the area you wish to target, and straighten the knees without locking them. This will be your starting position.','Raise your heels as you breathe out by extending your ankles as high as possible and flexing your calf. Ensure that the knee is kept stationary at all times. There should be no bending at any time. Hold the contracted position by a second before you start to go back down.','Go back slowly to the starting position as you breathe in by lowering your heels as you bend the ankles until calves are stretched.','Repeat for the recommended amount of repetitions.'], ARRAY['calves'], ARRAY[]::TEXT[], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Double Kettlebell Alternating Hang Clean', 'kettlebells', true, 'kettlebells', 'intermediate', 'pull', 'compound', ARRAY['Place two kettlebells between your feet. To get in the starting position, push your butt back and look straight ahead.','Clean one kettlebell to your shoulder and hold on to the other kettlebell.','With a fluid motion, lower the top kettlebell while driving the bottom kettlebell up.'], ARRAY['hamstrings'], ARRAY['biceps','calves','forearms','glutes','lower back','quadriceps','traps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Double Kettlebell Jerk', 'kettlebells', true, 'kettlebells', 'intermediate', 'push', 'compound', ARRAY['Hold a kettlebell by the handle in each hand.','Clean the kettlebells to your shoulders by extending through the legs and hips as you pull the kettlebells towards your shoulders. Rotate your wrists as you do so, so that the palms face forward. This will be your starting position.','Dip your body by bending the knees, keeping your torso upright.','Immediately reverse direction, driving through the heels, in essence jumping to create momentum.','As you do so, press the kettlebells overhead to lockout by extending the arms, using your body''s momentum to move the weights.','Return your feet to the ground in a split fashion, with one foot forward and one foot back.','Keeping the weights overhead, return to a standing position, bringing your feet together. Lower the weights to perform the next repetition.'], ARRAY['shoulders'], ARRAY['calves','quadriceps','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Double Kettlebell Push Press', 'kettlebells', true, 'kettlebells', 'intermediate', 'push', 'compound', ARRAY['Clean two kettlebells to your shoulders.','Squat down a few inches and reverse the motion rapidly. Use the momentum from the legs to drive the kettlebells overhead.','Once the kettlebells are locked out, lower the kettlebells to your shoulders and repeat.'], ARRAY['shoulders'], ARRAY['calves','quadriceps','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Double Kettlebell Snatch', 'kettlebells', true, 'kettlebells', 'expert', 'pull', 'compound', ARRAY['Place two kettlebells behind your feet. Bend your knees and sit back to pick up the kettlebells.','Swing the kettlebells between your legs forcefully and reverse the direction.','Drive through with your hips and lock the ketttlebells overhead in one uninterrupted motion.'], ARRAY['shoulders'], ARRAY['glutes','hamstrings','quadriceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Double Kettlebell Windmill', 'kettlebells', true, 'kettlebells', 'intermediate', 'pull', NULL, ARRAY['Place a kettlebell in front of your front foot and clean and press a kettlebell overhead with your opposite arm. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulders. Rotate your wrist as you do so, so that the palm faces forward.','Keeping the kettlebell locked out at all times, push your butt out in the direction of the locked out kettlebell. Turn your feet out at a forty-five degree angle from the arm with the locked out kettlebell.','Bending at the hip to one side, sticking your butt out, slowly lean until you can retrieve the kettlebell from the floor. Keep your eyes on the kettlebell that you hold over your head at all times.','Pause for a second after retrieving the kettlebell from the ground and reverse the motion back to the starting position.'], ARRAY['abdominals'], ARRAY['glutes','hamstrings','shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Double Leg Butt Kick', 'body only', true, 'body only', 'beginner', 'push', 'compound', ARRAY['Begin standing with your knees slightly bent.','Quickly squat a short distance, flexing the hips and knees, and immediately extend to jump for maximum vertical height.','As you go up, tuck your heels by flexing the knees, attempting to touch the buttocks.','Finish the motion by landing with the knees only partially bent, using your legs to absorb the impact.'], ARRAY['quadriceps'], ARRAY['abductors','adductors','calves','glutes','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Downward Facing Balance', 'exercise ball', true, 'exercise ball', 'intermediate', 'static', 'isolation', ARRAY['Lie facedown on top of an exercise ball.','While resting on your stomach on the ball, walk your hands forward along the floor and lift your legs, extending your elbows and knees.'], ARRAY['glutes'], ARRAY['abdominals','hamstrings'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Drag Curl', 'barbell', true, 'barbell', 'intermediate', 'pull', 'compound', ARRAY['Grab a barbell with a supinated grip (palms facing forward) and get your elbows close to your torso and back. This will be your starting position.','As you exhale, curl the bar up while keeping the elbows to the back as you Drag the bar up by keeping it in contact with your torso. Tip: As you can see, you will not be keeping the elbows pinned to your sides, but instead you will be bringing them back. Also, do not lift your shoulders.','Slowly go back to the starting position as you keep the bar in contact with the torso at all times.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Drop Push', 'other', true, 'other', 'intermediate', 'push', 'compound', ARRAY['Position low boxes or other platforms 2-3 feet apart.','Move to a pushup position between them, supporting yourself by placing your hands on the boxes.','With good posture, drop from the platforms by pressing up and moving your hands to shoulder width, cushioning your landing by absorbing the impact through the arm.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Alternate Bicep Curl', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Stand (torso upright) with a dumbbell in each hand held at arms length. The elbows should be close to the torso and the palms of your hand should be facing your thighs.','While holding the upper arm stationary, curl the right weight as you rotate the palm of the hands until they are facing forward. At this point continue contracting the biceps as you breathe out until your biceps is fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second as you squeeze the biceps. Tip: Only the forearms should move.','Slowly begin to bring the dumbbell back to the starting position as your breathe in. Tip: Remember to twist the palms back to the starting position (facing your thighs) as you come down.','Repeat the movement with the left hand. This equals one repetition.','Continue alternating in this manner for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Bench Press', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Lie down on a flat bench with a dumbbell in each hand resting on top of your thighs. The palms of your hands will be facing each other.','Then, using your thighs to help raise the dumbbells up, lift the dumbbells one at a time so that you can hold them in front of you at shoulder width.','Once at shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. The dumbbells should be just to the sides of your chest, with your upper arm and forearm creating a 90 degree angle. Be sure to maintain full control of the dumbbells at all times. This will be your starting position.','Then, as you breathe out, use your chest to push the dumbbells up. Lock your arms at the top of the lift and squeeze your chest, hold for a second and then begin coming down slowly. Tip: Ideally, lowering the weight should take about twice as long as raising it.','Repeat the movement for the prescribed amount of repetitions of your training program.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY['Press dumbbells up and slightly together','Lower until upper arms parallel to floor','Keep shoulder blades pinched entire set','Squeeze chest hard at top','Rotate palms to face each other slightly for shoulder comfort'], ARRAY['Going too deep and straining shoulders','Dumbbells drifting too wide at bottom','Losing control on the negative'])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Bench Press with Neutral Grip', 'dumbbell', true, 'dumbbell', 'beginner', 'push', 'compound', ARRAY['Take a dumbbell in each hand and lay back onto a flat bench. Your feet should be flat on the floor and your shoulder blades retracted.','Maintaining a neutral grip, palms facing each other, begin with your arms extended directly above you, perpendicular to the floor. This will be your starting position.','Begin the movement by flexing the elbow, lowering the upper arms to the side. Descend until the dumbbells are to your torso.','Pause, then extend the elbow and return to the starting position.'], ARRAY['chest'], ARRAY['shoulders','triceps'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
ON CONFLICT DO NOTHING;

INSERT INTO exercises (name, category, is_public, equipment, level, force, mechanic, instructions, primary_muscles, secondary_muscles, coaching_cues, common_mistakes)
VALUES ('Dumbbell Bicep Curl', 'dumbbell', true, 'dumbbell', 'beginner', 'pull', 'isolation', ARRAY['Stand up straight with a dumbbell in each hand at arm''s length. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position.','Now, keeping the upper arms stationary, exhale and curl the weights while contracting your biceps. Continue to raise the weights until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a brief pause as you squeeze your biceps.','Then, inhale and slowly begin to lower the dumbbells back to the starting position.','Repeat for the recommended amount of repetitions.'], ARRAY['biceps'], ARRAY['forearms'], ARRAY[]::TEXT[], ARRAY[]::TEXT[])
